var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정신차려! 이 근육 바보야!","JPN":"しっかりして！　この脳筋バカ！","ENG":"Wake up, you muscle-bound idiot!","TWN":"肌肉傻瓜！你醒醒！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"대체 어쩌다가 이런 꼴이 된 거야?","JPN":"いったい何をしたらこんなことになるの！？","ENG":"What happened to you?","TWN":"你怎麼會變成這樣？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"6번 수술실 준비되었습니다! 실비아 씨, 지금 바로 이송해야 합니다!","JPN":"6番手術室の用意ができました！\\nシルビアさん、すぐに移送しなければいけません！","ENG":"Operation Room #6 is ready! Sylvia, we have to move him now!","TWN":"6號手術室已經準備妥當！希爾維亞，必須立刻送他進手術室！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 멍청이 괜찮은 거 맞지? 혹시 잘못 되는 거 아니지?","JPN":"このバカ、大丈夫なんだよね？　治療すれば治るよね？","ENG":"He will be okay, right? Tell me that idiot will be okay!","TWN":"這個傻瓜沒事吧？應該不會有事吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……과도한 능력 사용으로 번개가 역류해서 자신의 몸까지 태워 버린 것으로 보입니다.","JPN":"……過度な能力使用で電力が逆流してしまい、\\n自身の体まで燃えてしまったようです。","ENG":"It looks like he overused his power and it backfired on him, burning his body.","TWN":"……可能是因為他過度使用能力，導致閃電逆流燒到自己的身上。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"일반적인 카운터라면 그럴 일이 없겠지만 대령님은 CRF 출력이 너무 강력해서……","JPN":"普通のカウンターならそんなことは起こらないと思いますが、\\n大佐はCRF出力があまりにも強すぎて……","ENG":"If he was an ordinary Counter, this wouldn't have happened, but the Colonel has such a high CRF output...","TWN":"通常一般的制裁者不會發生這種事，但上校的CRF輸出太強……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그딴 건 안 궁금해! 아무튼 괜찮은 거냐고?!","JPN":"そんなことを聞いてるんじゃないわよ！\\nとにかく彼は大丈夫なのかって聞いてるの！","ENG":"I didn’t ask that! I asked if he was going to be okay!","TWN":"我不想知道這些！我只想知道他是不是沒事？！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실…… 비아……","JPN":"シル……ビア……","ENG":"Sylvia...","TWN":"希……爾維亞……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님!","JPN":"大佐！","ENG":"Colonel!","TWN":"上校！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저, 정신이 들어? 이 멍청아! 대체 무슨 일을 저지른 거야!","JPN":"だ、大丈夫？　このバカ！　いったい何をしたの！？","ENG":"A-are you awake? You idiot! What have you done?","TWN":"你…你醒了嗎？你這個傻瓜！你到底做了什麼！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"중장님께 배운 대로…… 해야 할 일을 했을 뿐이야……","JPN":"中将に教わったとおり……やるべきことをしただけさ……","ENG":"I did... what the Lieutenant General taught me...","TWN":"我只是照著中將教我的……做我該做的事……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"걱정 마…… 이 정도로 죽을 만큼…… 내가 약골로…… 보여……?","JPN":"心配すんな……この程度でくたばるほど……俺はヤワ……じゃないぞ……","ENG":"Don’t worry... I won’t die... I’m not that weak...","TWN":"放心……這點小傷死不了的……我有……那麼弱嗎……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당연히 아니지!","JPN":"わかってるわよ！","ENG":"Of course not!","TWN":"當然不是！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아씨! 이제 정말 이송해야 합니다!","JPN":"シルビアさん！　もう移送しないと！","ENG":"Sylvia, he really has to go!","TWN":"希爾維亞！真的該送他進手術室了！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかったわよ！","ENG":"O-okay!","TWN":"喔…好！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죄송합니다……. 제가 조금만 더 잘했다면 이런 일은 없었을 텐데…….","JPN":"すみません……私がもっとうまくやれたらこんなことには……","ENG":"I’m sorry... I should have done better...","TWN":"抱歉……都怪我不夠堅強，才會發生這種事……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당신도 온 몸이 만신창이로 보이는데…….","JPN":"アンタも全身にひどい怪我をしてるじゃない……","ENG":"But you’re seriously hurt, too...","TWN":"我看你也傷得不輕……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};